def serialize_account_exposure(account: dict[str, Any]) -> dict[str, Any]:
    """Project one stored exposure account into the public account.exposure shape."""
    return {
        "maxPositionSize": round_risk_value(max_position_size),
        "updatedAt": str(account["updatedAt"]),
        "positions": serialize_account_exposure_positions(account),
    }


def get_account_exposure_projection_state(account_id: str) -> dict[str, Any]:
    """Return one exposure-backed account document or raise projection-local 404."""
    account = ACCOUNT_EXPOSURE.get(account_id)
    if account is None:
        raise ApiError(404, "account_not_found", "Account not found", {"accountId": account_id})
    return account


def get_account_exposure(account_id: str) -> tuple[dict[str, Any], int]:
    """Return the read model for one account's current live EventTrade exposure."""
    account = get_account_exposure_projection_state(account_id)
    exposure = serialize_account_exposure(account)
    if not exposure["positions"]:
        # Exposure existence is projection-local: once all live rows are pruned,
        # the account disappears from this read model and resolves as 404 again.
        raise ApiError(404, "account_not_found", "Account not found", {"accountId": account_id})

    return {
        "account": {
            "id": account_id,
            "exposure": exposure,
        },
        "meta": make_meta(),
    }, 200


def get_account_positions(account_id: str) -> tuple[dict[str, Any], int]:
    """Return the read model for one account's current live open positions."""
    account = get_account_exposure_projection_state(account_id)

def test_event_trade_accepts_exact_max_position_boundary_without_widening_contract(self):
    for case in (
        {
            "label": "positive-cap-buy",
            "account_id": "acct_event_trade_exact_positive",
            "starting_net_size": 99.5,
            "side": "buy",
            "size": 0.5,
            "expected_net_size": 100.0,
        },
        {
            "label": "negative-cap-sell",
            "account_id": "acct_event_trade_exact_negative",
            "starting_net_size": -99.5,
            "side": "sell",
            "size": 0.5,
            "expected_net_size": -100.0,
        },
    ):
        with self.subTest(case=case["label"]):
            server.reset_state()
            account_id = case["account_id"]
            server.ACCOUNT_EXPOSURE[account_id] = {
                "accountId": account_id,
                "updatedAt": "2026-04-09T12:00:00Z",
                "positions": {
                    "m1|yes": {
                        "marketId": "m1",
                        "outcomeId": "yes",
                        "netSize": case["starting_net_size"],
                        "lastTradePrice": 0.65,
                        "updatedAt": "2026-04-09T11:55:00Z",
                        "lastOrderId": "ord_seed",
                        "lastCommandId": "cmd_seed",
                    }
                },
            }

            payload, status = server.route_request(
                "POST",
                "/v1/markets/m1/orders/event-trade",
                build_event_trade_body(
                    account_id,
                    "m1",
                    "yes",
                    size=case["size"],
                    side=case["side"],
                ),
            )

